      parseExistingCodes(content) {
        const codes = [];
        if (!content)
          return codes;
        const lines = content.split("\n");
        for (const line of lines) {
          if (!line.trim() || line.startsWith("##") || line.startsWith("| ---") || line.startsWith("<!--")) {
            continue;
          }
          if (line.includes("|")) {
            const parts = line.split("|").map((p) => p.trim());
            if (parts.length >= 3) {
              let code = parts[2];
              if (code) {
                code = code.replace(/\[\[|\]\]/g, "");
                if (code.includes("|")) {
                  code = code.split("|")[1];
                }
                if (code && /^\d{2}_\d{4}_[A-Z]/.test(code)) {
                  codes.push(code);
                }
              }
            }
          }
        }
        return codes;
      }
